const titleCase = (name) => name.charAt(0).toUpperCase() + name.slice(1);

const HEADER = (what) =>
  `# ApostropheCMS — ${what} environment configuration.
# Generated by create-apostrophe. This file is gitignored.
# Keep these values private; do not commit real secrets.
`;

const SECRETS = `
# Session secret used to sign cookies.
APOS_SESSION_SECRET=

# Secures access to disabled (e.g. trashed) uploaded files.
APOS_UPLOADFS_DISABLED_FILE_KEY=

# The database connection string for the database you chose is added
# below by the installer (SQLite needs none).
`;

/** Standalone full-stack project: a single `.env` at the project root. */
export function standaloneEnv() {
  return HEADER('project') + SECRETS;
}

/**
 * Apostrophe backend `.env` for a project with an external frontend.
 * @param {string} name External-frontend name (e.g. `'astro'`) — labels the
 *   file; the keys are the same for any external frontend.
 */
export function externalBackendEnv(name) {
  return `${HEADER(`${titleCase(name)} backend`)}
# Required for local development when using the external frontend
APOS_EXTERNAL_FRONT_KEY=dev
# Set to 1 to enable development mode (always fully rebuilds, no stale admin UI)
APOS_DEV=1
${SECRETS}`;
}

/**
 * External-frontend `.env` (no secrets — only the shared front key).
 * @param {string} name External-frontend name (e.g. `'astro'`).
 */
export function externalFrontendEnv(name) {
  return `${HEADER(`${titleCase(name)} frontend`)}
# Required for local development — must match APOS_EXTERNAL_FRONT_KEY in the backend
APOS_EXTERNAL_FRONT_KEY=dev
`;
}

/** Keys the scaffold step fills with generated secrets (frontend gets none). */
export const SECRET_KEYS = Object.freeze([
  'APOS_SESSION_SECRET',
  'APOS_UPLOADFS_DISABLED_FILE_KEY'
]);
